weight: var(--pet-font-weight-semibold);\n  color: var(--pet-color-text-faint);\n}\n.pet-ctx__chips {\n  display: flex;\n  flex-wrap: wrap;\n  align-items: center;\n  gap: var(--pet-space-xs);\n  flex: 1;\n  min-width: 0;\n}\n</style>\n"],"sourceRoot":""}]);
